sys_script_include.script:
var AlationRegistration = Class.create();
AlationRegistration.prototype = {
  initialize: function() {},

  registerWithGoService: function(alationHost, tenantId, method, token) {
    var utils = new AlationUtils();
    var host = utils.normalizeHost(alationHost);
    if (!host) return { ok:false, reason:'alation_host is missing or invalid' };

    var goBase = "https://" + host;
    var registerUrl = goBase + "/snow/api/integration/register";

    // ---- NEW: discover OAuth config from fixed registry + fixed user
    var discovery = new AlationOAuthDiscovery().discover();
    if (!discovery.ok) {
      return { ok:false, reason: discovery.error || 'OAuth discovery failed' };
    }

    var base = utils.apiBase();
    var payload = {
      provider: "servicenow",
      create_incident_url:  base + "/incident",
      get_incident_url:     base + "/incident",
      update_incident_url:  base + "/incident",
      list_impacts_url:     base + "/impacts",
      list_urgencies_url:   base + "/urgencies",
      list_categories_url:  base + "/categories",
      list_assignment_groups_url: base + "/assignment-groups",
      list_subcategories_url: base + "/subcategories",

      token: token || utils.getOrCreateApiKey(),

      oauth: discovery.oauth
    };

    var bodyStr = JSON.stringify(payload);

    // NOTE: This HMAC is for SN->Go registration/auth currently. Keep for now if Go still expects it.
    var hmac = new AlationHmacJS();
    var sig = hmac.buildSigHeaders(tenantId, bodyStr);

    var r = new sn_ws.RESTMessageV2();
    r.setEndpoint(registerUrl);
    r.setHttpMethod(String(method || 'POST'));
    r.setRequestHeader("Content-Type","application/json");
    r.setRequestHeader("Accept","application/json");

    r.setRequestHeader("x-tenant-id", String(tenantId || ''));
    r.setRequestHeader("Cookie", "service.zeus.tenant.id=" + tenantId);

    r.setRequestHeader("x-timestamp", sig['x-timestamp']);
    r.setRequestHeader("x-signature", sig['x-signature']);

    r.setRequestBody(bodyStr);
    r.setHttpTimeout(15000);

    try {
      var res = r.execute();
      var sc = res.getStatusCode(), body = res.getBody();
      gs.info('[x_alati_dpm_serv_0] Register ' + (method || 'POST') + ' ' + registerUrl + ' status=' + sc);
      if (sc < 200 || sc >= 300) {
        gs.error('[x_alati_dpm_serv_0] Register failed: ' + sc + ' body=' + body);
        return { ok:false, status:sc, reason:'Registration failed', body:body };
      }
      return { ok:true };
    } catch (ex) {
      gs.error('[x_alati_dpm_serv_0] Register threw: ' + ex);
      return { ok:false, reason:'Registration exception: ' + ex };
    }
  },

  type: "AlationRegistration"
};
